import { formatCostUsd, formatDurationMs, formatRate, formatTokensOrDash } from "./format.ts";

function renderKey(dimension: "agent" | "model", key: string): React.ReactNode {
	if (key === RUN_ANALYTICS_NONE_KEY) {
		return <span className="text-(--color-muted-foreground)">—</span>;
	}
	if (dimension === "agent") {
		return (
			<Link
				to={`/agents/${encodeURIComponent(key)}`}
				className="underline-offset-2 hover:underline"
			>
				{key}
			</Link>
		);
	}
	return <span className="font-mono text-xs">{key}</span>;
}

export function GroupTable({
	title,
	subtitle,
	dimension,
	buckets,
	loading,
}: {
	title: string;
	subtitle: string;
	dimension: "agent" | "model";
	buckets: RunGroupBucket[];
	loading: boolean;
}) {
	return (
		<Card>
			<CardHeader>
				<CardTitle className="text-base">{title}</CardTitle>
				<p className="text-xs text-(--color-muted-foreground)">{subtitle}</p>
			</CardHeader>
			<CardContent>
				{loading ? (
					<p className="text-sm text-(--color-muted-foreground)">Loading…</p>
				) : buckets.length === 0 ? (
					<p className="text-sm text-(--color-muted-foreground)">No data in this window.</p>
				) : (
					<Table>
						<TableHeader>
							<TableRow>
								<TableHead>{dimension === "agent" ? "Agent" : "Model"}</TableHead>
								<TableHead className="text-right">Runs</TableHead>
								<TableHead className="text-right">Success</TableHead>
								<TableHead className="text-right">Avg ctx</TableHead>
								<TableHead className="text-right">Avg dur</TableHead>
								<TableHead className="text-right">Cost</TableHead>
							</TableRow>
						</TableHeader>
						<TableBody>
							{buckets.map((b) => (
								<TableRow key={b.key}>
									<TableCell className="max-w-[260px] truncate">
										{renderKey(dimension, b.key)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs text-(--color-muted-foreground)">
										{b.runs}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs">
										{formatRate(b.successRate)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs">
										{formatTokensOrDash(b.avgContextTokens)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs text-(--color-muted-foreground)">
										{formatDurationMs(b.avgDurationMs)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs">
										{formatCostUsd(b.costUsd)}
									</TableCell>
								</TableRow>
							))}
						</TableBody>
					</Table>
				)}
			</CardContent>
		</Card>
	);
}

/**
 * Formatting helpers for the Run Analytics dashboard (warren-638a /
 * pl-ad0f step 5).
 *
 * Kept in a dedicated module so the page + its sub-components share one
 * set of token / duration / percentage formatters without re-importing
 * RunDetail internals (formatTokens there is module-private). The cost
 * formatter is the one shared piece — re-exported from RunDetail so the
 * sub-cent rounding rule (mx-9d987a) stays in lockstep.
 */
export { formatCostUsd } from "../RunDetail.tsx";

/** 1_234_567 → "1.2M", 12_345 → "12.3k", 999 → "999". */
export function formatTokens(n: number): string {
	if (n >= 1_000_000) return `${(n / 1_000_000).toFixed(1)}M`;
	if (n >= 1_000) return `${(n / 1_000).toFixed(1)}k`;
	return String(Math.round(n));
}

/** Round-trip a possibly-null token count through formatTokens, em-dash on null. */
export function formatTokensOrDash(n: number | null): string {
	return n === null ? "—" : formatTokens(n);
}

/** Milliseconds → compact human duration ("4.2s", "3.1m", "1.4h"). */
export function formatDurationMs(ms: number | null): string {
	if (ms === null) return "—";
	if (ms < 1_000) return `${Math.round(ms)}ms`;
	const s = ms / 1_000;
	if (s < 60) return `${s.toFixed(1)}s`;
	const m = s / 60;
	if (m < 60) return `${m.toFixed(1)}m`;
	return `${(m / 60).toFixed(1)}h`;
}

/** 0..1 ratio → "92%", null → "—". */
export function formatRate(rate: number | null): string {
	if (rate === null) return "—";
	return `${Math.round(rate * 100)}%`;
}

/** Integer count, em-dash when the underlying value is null. */
export function formatCount(n: number | null): string {
	return n === null ? "—" : n.toLocaleString();
}

/**
 * Recharts surface for the Run Analytics dashboard (warren-638a /
 * pl-ad0f step 5).
 *
 * Four charts, each fed straight off the `GET /analytics/runs`
 * envelope and wrapped in the shared `ChartContainer` seam
 * (warren-876c) so recharts stays behind one import boundary:
 *
 *   - RunsOverTimeChart  — stacked area of per-state run counts per day
 *   - AvgContextPerAgentChart — bar of avg context tokens by agent
 *   - TopSeedsByContextChart  — bar of total context tokens by seed
 *   - FailureReasonChart      — pie of failed-run counts by reason
 *
 * Charts render a muted "No data in this window." placeholder rather
 * than an empty axis frame when their slice of the payload is empty.
 */
import type {
	RunDayBucket,
	RunFailureBucket,
	RunGroupBucket,
	SeedContextBucket,
} from "@/api/client.ts";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card.tsx";
import {
