/**
 * Derived-insights callout cards for the Run Analytics dashboard —
 * Phase 2 (warren-436a / pl-ad0f step 10).
 *
 * Renders the ranked, severity-coded `Insight[]` from
 * `GET /analytics/behavior` as a row of callout cards at the top of the
 * behavior section. Each card colors its left border + severity badge
 * by `severity` (critical → destructive, warning → warning, info →
 * info). The list is pre-sorted server-side (severity, then kind), so
 * the UI just maps it. Renders nothing when there are no insights so the
 * section collapses cleanly on a quiet window.
 */
import type { Insight, InsightSeverity } from "@/api/client.ts";
import { Card, CardContent } from "@/components/ui/card.tsx";

const SEVERITY_STYLE: Record<
	InsightSeverity,
	{ border: string; badge: string; label: string }
> = {
	critical: {
		border: "border-l-(--color-destructive)",
		badge: "bg-(--color-destructive) text-(--color-destructive-foreground)",
		label: "Critical",
	},
	warning: {
		border: "border-l-(--color-warning)",
		badge: "bg-(--color-warning) text-(--color-warning-foreground)",
		label: "Warning",
	},
	info: {
		border: "border-l-(--color-info)",
		badge: "bg-(--color-info) text-(--color-info-foreground)",
		label: "Info",
	},
};

function InsightCard({ insight }: { insight: Insight }) {
	const style = SEVERITY_STYLE[insight.severity];
	return (
		<Card className={`border-l-4 ${style.border}`}>
			<CardContent className="space-y-2 py-4">
				<div className="flex items-start justify-between gap-2">
					<h3 className="text-sm font-medium">{insight.title}</h3>
					<span
						className={`shrink-0 rounded-full px-2 py-0.5 text-[10px] font-semibold uppercase tracking-wide ${style.badge}`}
					>
						{style.label}
					</span>
				</div>
				<p className="text-xs text-(--color-muted-foreground)">{insight.detail}</p>
				{insight.subject !== null ? (
					<p className="font-mono text-[11px] text-(--color-muted-foreground)">
						{insight.subject}
					</p>
				) : null}
			</CardContent>
		</Card>
	);
}

export function InsightCallouts({ insights }: { insights: Insight[] }) {
	if (insights.length === 0) return null;
	return (
		<div className="grid grid-cols-1 gap-4 md:grid-cols-2 lg:grid-cols-3">
			{insights.map((insight) => (
				<InsightCard key={`${insight.kind}:${insight.subject ?? ""}`} insight={insight} />
			))}
		</div>
	);
}

/**
 * Command-mining surface for the Run Analytics dashboard — Phase 2
 * (warren-436a / pl-ad0f step 10).
 *
 * Two views over the `mining` envelope from `GET /analytics/behavior`:
 *
 *   - CommandCategoryChart — bar of command invocations per generalized
 *     category (os-eco, vcs, package, build, test, …), failures overlaid.
 *   - StuckCommandTable — the stuck-command leaderboard (`byStuckScore`,
 *     pre-sorted desc): commands re-run after failing in the same run.
 *     os-eco tooling (`ml`/`sd`/`gh`/`bun run check:*`) is highlighted.
 *
 * Both degrade to a muted "No data in this window." placeholder when
 * their slice of the payload is empty.
 */
import type { CommandCategoryBucket, CommandStat } from "@/api/client.ts";
import { Badge } from "@/components/ui/badge.tsx";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card.tsx";
import {
	Bar,
	BarChart,
	CartesianGrid,
	ChartContainer,
	Legend,
	Tooltip,
	XAxis,
	YAxis,
} from "@/components/ui/chart.tsx";
import {
	Table,
	TableBody,
	TableCell,
	TableHead,
	TableHeader,
	TableRow,
} from "@/components/ui/table.tsx";
import { formatRate } from "./format.ts";

const AXIS_PROPS = {
	stroke: "var(--color-muted-foreground)",
	fontSize: 11,
	tickLine: false,
	axisLine: false,
} as const;

const TOOLTIP_STYLE = {
	backgroundColor: "var(--color-card)",
	border: "1px solid var(--color-border)",
	borderRadius: 6,
	fontSize: 12,
} as const;

export function CommandCategoryChart({ byCategory }: { byCategory: CommandCategoryBucket[] }) {
	return (
		<Card>
			<CardHeader>
				<CardTitle className="text-base">Commands by category</CardTitle>
				<p className="text-xs text-(--color-muted-foreground)">
					Tool invocations per generalized command category, with failures overlaid
				</p>
			</CardHeader>
			<CardContent>
				{byCategory.length === 0 ? (
					<p className="py-6 text-sm text-(--color-muted-foreground)">
						No data in this window.
					</p>
				) : (
					<ChartContainer>
						<BarChart data={byCategory} margin={{ top: 8, right: 8, bottom: 0, left: -16 }}>
							<CartesianGrid
								strokeDasharray="3 3"
								stroke="var(--color-border)"
								vertical={false}
							/>
							<XAxis dataKey="category" {...AXIS_PROPS} interval={0} />
							<YAxis allowDecimals={false} {...AXIS_PROPS} />
							<Tooltip contentStyle={TOOLTIP_STYLE} />
							<Legend wrapperStyle={{ fontSize: 11 }} />
							<Bar
								dataKey="invocations"
								name="invocations"
								fill="var(--color-info)"
								radius={[3, 3, 0, 0]}
							/>
							<Bar
								dataKey="failures"
								name="failures"
								fill="var(--color-destructive)"
								radius={[3, 3, 0, 0]}
							/>
						</BarChart>
					</ChartContainer>
				)}
			</CardContent>
		</Card>
	);
}

function renderCommand(stat: CommandStat): React.ReactNode {
	return (
		<span className="flex items-center gap-2">
			<span className="font-mono text-xs">{stat.command}</span>
			{stat.osEco ? (
				<Badge variant="active" className="shrink-0">
					os-eco
				</Badge>
			) : null}
		</span>
	);
}

export function StuckCommandTable({ byStuckScore }: { byStuckScore: CommandStat[] }) {
	return (
		<Card>
			<CardHeader>
				<CardTitle className="text-base">Stuck-command leaderboard</CardTitle>
				<p className="text-xs text-(--color-muted-foreground)">
					Commands re-run after failing earlier in the same run — the "stuck in a loop" signal
				</p>
			</CardHeader>
			<CardContent>
				{byStuckScore.length === 0 ? (
					<p className="text-sm text-(--color-muted-foreground)">No stuck commands in this window.</p>
				) : (
					<Table>
						<TableHeader>
							<TableRow>
								<TableHead>Command</TableHead>
								<TableHead className="text-right">Stuck</TableHead>
								<TableHead className="text-right">Retries</TableHead>
								<TableHead className="text-right">Fails</TableHead>
								<TableHead className="text-right">Fail rate</TableHead>
								<TableHead className="text-right">Runs</TableHead>
							</TableRow>
						</TableHeader>
						<TableBody>
							{byStuckScore.map((stat) => (
								<TableRow
									key={stat.command}
									className={stat.osEco ? "bg-(--color-info)/5" : undefined}
								>
									<TableCell className="max-w-[320px] truncate">
										{renderCommand(stat)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs text-(--color-destructive)">
										{stat.stuckScore}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs text-(--color-muted-foreground)">
										{stat.retries}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs">
										{stat.failures}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs">
										{formatRate(stat.failureRate)}
									</TableCell>
									<TableCell className="whitespace-nowrap text-right font-mono text-xs text-(--color-muted-foreground)">
										{stat.runs}
									</TableCell>
								</TableRow>
							))}
						</TableBody>
					</Table>
				)}
			</CardContent>
		</Card>
	);
}

